patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..d2b2926a511f 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1317,6 +1317,7 @@ static Value *foldAndOrOfICmpsWithConstEq(ICmpInst *Cmp0, ICmpInst *Cmp1,
 /// or   (icmp Pred1 V1, C1) | (icmp Pred2 V2, C2)
 /// into a single comparison using range-based reasoning.
 /// NOTE: This is also used for logical and/or, must be poison-safe!
+
 Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
                                                      ICmpInst *ICmp2,
                                                      bool IsAnd) {
@@ -1338,30 +1339,20 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
       V2 = X;
   }

-  // Look through and with a negative power of 2 mask on V1 or V2. This
-  // detects idioms of the form `(x == A) || ((x & Mask) == A + 1)` where A + 1
-  // is aligned to the mask and A + 1 >= |Mask|. This pattern corresponds to a
-  // contiguous range check, which can be folded into an addition and compare.
-  // The same applies for `(x != A) && ((x & Mask) != A + 1)`.
-  auto AreContiguousRangePredicates = [](CmpPredicate Pred1, CmpPredicate Pred2,
-                                         bool IsAnd) {
-    if (IsAnd)
-      return Pred1 == ICmpInst::ICMP_NE && Pred2 == ICmpInst::ICMP_NE;
-    return Pred1 == ICmpInst::ICMP_EQ && Pred2 == ICmpInst::ICMP_EQ;
-  };
+  // Look through and with a mask on V1 or V2. This detects idioms where one
+  // comparison uses a masked value.
   const APInt *Mask1 = nullptr, *Mask2 = nullptr;
   bool MatchedAnd1 = false, MatchedAnd2 = false;
-  if (V1 != V2 && AreContiguousRangePredicates(Pred1, Pred2, IsAnd)) {
+  if (V1 != V2) {
     Value *X;
-    if (match(V1, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask1)))) &&
-        C1->getBitWidth() == C2->getBitWidth() && *C1 == *C2 + 1 &&
-        C1->uge(Mask1->abs()) && C1->isPowerOf2()) {
+    // Check for (V & Mask) in either operand.
+    if (match(V1, m_OneUse(m_And(m_Value(X), m_APInt(Mask1)))) &&
+        C1->getBitWidth() == Mask1->getBitWidth()) {
       MatchedAnd1 = true;
       V1 = X;
     }
-    if (match(V2, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask2)))) &&
-        C1->getBitWidth() == C2->getBitWidth() && *C2 == *C1 + 1 &&
-        C2->uge(Mask2->abs()) && C2->isPowerOf2()) {
+    if (match(V2, m_OneUse(m_And(m_Value(X), m_APInt(Mask2)))) &&
+        C2->getBitWidth() == Mask2->getBitWidth()) {
       MatchedAnd2 = true;
       V2 = X;
     }
@@ -1370,19 +1361,52 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   if (V1 != V2)
     return nullptr;

-  ConstantRange CR1 =
-      MatchedAnd1
-          ? ConstantRange(*C1, *C1 - *Mask1)
-          : ConstantRange::makeExactICmpRegion(
-                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
+  // Helper to compute range for (X & Mask) Pred C
+  auto ComputeMaskedRange = [](CmpPredicate Pred, const APInt &C,
+                               const APInt &Mask) -> ConstantRange {
+    unsigned BitWidth = C.getBitWidth();
+    
+    // For equality comparisons: (X & Mask) == C
+    if (Pred == ICmpInst::ICMP_EQ) {
+      // Solutions exist only if (C & ~Mask) == 0
+      if ((C & ~Mask) != 0)
+        return ConstantRange::getEmpty(BitWidth);
+      
+      // Find free bits (bits where Mask is 0)
+      APInt FreeMask = ~Mask;
+      if (FreeMask == 0)
+        return ConstantRange(C, C + 1);  // Single value
+      
+      // The solution set is all values X where X & Mask == C
+      APInt MinVal = C;
+      APInt MaxVal = C | FreeMask;
+      return ConstantRange(MinVal, MaxVal + 1);
+    }
+    
+    // For other predicates, use the standard exact region
+    return ConstantRange::makeExactICmpRegion(Pred, C);
+  };
+
+  // Compute ranges for the original comparisons (for subset checking)
+  ConstantRange OriginalCR1 = MatchedAnd1
+                          ? ComputeMaskedRange(Pred1, *C1, *Mask1)
+                          : ConstantRange::makeExactICmpRegion(Pred1, *C1);
+  ConstantRange OriginalCR2 = MatchedAnd2
+                          ? ComputeMaskedRange(Pred2, *C2, *Mask2)
+                          : ConstantRange::makeExactICmpRegion(Pred2, *C2);
+  
+  // Compute ranges for union/intersection logic (inverted for AND)
+  ConstantRange CR1 = MatchedAnd1
+                          ? ComputeMaskedRange(Pred1, *C1, *Mask1)
+                          : ConstantRange::makeExactICmpRegion(
+                                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
   if (Offset1)
     CR1 = CR1.subtract(*Offset1);

-  ConstantRange CR2 =
-      MatchedAnd2
-          ? ConstantRange(*C2, *C2 - *Mask2)
-          : ConstantRange::makeExactICmpRegion(
-                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
+  ConstantRange CR2 = MatchedAnd2
+                          ? ComputeMaskedRange(Pred2, *C2, *Mask2)
+                          : ConstantRange::makeExactICmpRegion(
+                                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);

@@ -1407,8 +1431,42 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
     NewV = Builder.CreateAnd(NewV, ConstantInt::get(Ty, ~LowerDiff));
   }

-  if (IsAnd)
+  // For AND, if one range contains the other, the result is the contained range
+  if (IsAnd) {
+    if (OriginalCR1.contains(OriginalCR2)) {
+      // OriginalCR2 is contained in OriginalCR1, so result is just OriginalCR2
+      if (Offset2)
+        NewV = Builder.CreateAdd(NewV, ConstantInt::get(Ty, *Offset2));
+      if (MatchedAnd2)
+        NewV = Builder.CreateAnd(NewV, ConstantInt::get(Ty, *Mask2));
+      return Builder.CreateICmp(Pred2, NewV, ConstantInt::get(Ty, *C2));
+    }
+    if (OriginalCR2.contains(OriginalCR1)) {
+      // OriginalCR1 is contained in OriginalCR2, so result is just OriginalCR1
+      if (Offset1)
+        NewV = Builder.CreateAdd(NewV, ConstantInt::get(Ty, *Offset1));
+      if (MatchedAnd1)
+        NewV = Builder.CreateAnd(NewV, ConstantInt::get(Ty, *Mask1));
+      return Builder.CreateICmp(Pred1, NewV, ConstantInt::get(Ty, *C1));
+    }
+    // Otherwise compute intersection of the original ranges
+    ConstantRange Intersection = OriginalCR1.intersectWith(OriginalCR2);
+    if (Intersection.isEmptySet())
+      return ConstantInt::getFalse(Ty);
+    
+    // Try to convert intersection to a single comparison
+    CmpInst::Predicate NewPred;
+    APInt NewC, Offset;
+    if (Intersection.getEquivalentICmp(NewPred, NewC, Offset)) {
+      if (Offset != 0)
+        NewV = Builder.CreateAdd(NewV, ConstantInt::get(Ty, Offset));
+      return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
+    }
+    return nullptr;
+  } else {
+    // For OR, use the union as before.
     CR = CR->inverse();
+  }

   CmpInst::Predicate NewPred;
   APInt NewC, Offset;
@@ -1419,6 +1477,7 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(Ty, NewC));
 }

+
 /// Ignore all operations which only change the sign of a value, returning the
 /// underlying magnitude value.
 static Value *stripSignOnlyFPOps(Value *Val) {
